console.log('Iniciando descompactação do Mira...');

let filesCreated = 0;
let dirsCreated = 0;

for (const [relPath, base64Content] of Object.entries(bundledFiles)) {
    const fullPath = path.join(__dirname, relPath);
    const dirName = path.dirname(fullPath);
    
    if (!fs.existsSync(dirName)) {
        fs.mkdirSync(dirName, { recursive: true });
        dirsCreated++;
    }
    
    fs.writeFileSync(fullPath, Buffer.from(base64Content, 'base64'));
    filesCreated++;
    console.log('Criado: ' + relPath);
}

// Criar pastas vazias obrigatórias para o funcionamento do Mira
const emptyDirs = ['decks', '.mira'];
emptyDirs.forEach(dir => {
    const fullPath = path.join(__dirname, dir);
    if (!fs.existsSync(fullPath)) {
        fs.mkdirSync(fullPath, { recursive: true });
        dirsCreated++;
        console.log('Pasta base criada: ' + dir + '/');
    }
});

console.log('\n======================================================');
console.log('🚀 Instalação concluída com sucesso!');
console.log('- Arquivos extraídos: ' + filesCreated);
console.log('- Pastas criadas: ' + dirsCreated);
console.log('======================================================');
console.log('Você já pode usar as skills do Mira no seu ambiente corporativo!');